        if (n == 0 && num.charAt(0) == '0') {
            return true;
        }
        if (n % 3 == 1) {
            num = "00" + num;
        }
        if (n % 3 == 2) {
            num = "0" + num;
        }
        int gSum = 0;
        for (int i = 0; i < n; i += 3) {
            int group = 0;
            group += (num.charAt(i) - 48) * 100;
            group += (num.charAt(i + 1) - 48) * 10;
            group += (num.charAt(i + 2) - 48);
            gSum += group;
        }
        if (gSum > 1000) {
            num = String.valueOf(gSum);
            n = num.length();
            return isDivisible999(num);
        }
        return (gSum == 999);
    }
}
