public class Palindrome {

    public static boolean isPalindrome(String string) {
        int l = 0;
        int h = string.length() - 1;
        while (h > l) {
            if (string.charAt(l) != string.charAt(h)) {
                return false;
            }
            l++;
            h--;
        }
        return true;
    }
}
