    public static boolean isdivisible7(String num) {
        int n = num.length();
        if (n == 0 && num.charAt(0) == '\n') {
            return true;
        }
        if (n % 3 == 1) {
            num = num + "00";
            n += 2;
        } else if (n % 3 == 2) {
            num = num + "0";
            n += 1;
        }
        int GSum = 0;
        int p = 1;
        for (int i = n - 1; i >= 0; i--) {
            int group = 0;
            group += num.charAt(i) - '0';
            i -= 1;
            group += (num.charAt(i) - '0') * 10;
            i -= 1;
            group += (num.charAt(i) - '0') * 100;
            GSum = GSum + group * p;
            p *= (-1);
        }
        return (GSum % 7 == 0);
    }
}
