public class Solution {
    public static int countOnes(int[] arr, int low, int high) {
        if (high >= low) {
            int mid = low + (high - low) / 2;
            if ((mid == high || arr[mid + 1] == 0) && (arr[mid] == 1)) {
                return mid + 1;
            }
            if (arr[mid] == 1) {
                return countOnes(arr, mid + 1, high);
            }
            return countOnes(arr, low, mid - 1);
        }
        return 0;
    }
}
