public static int countarray(int n, int k, int x) {
    List<Integer> dp = new ArrayList<>();
    dp.add(0);
    dp.add(1);
    int i = 2;
    while (i < n) {
        dp.add((k - 2) * dp.get(i - 1) + (k - 1) * dp.get(i - 2));
        i = i + 1;
    }
    return ((k - 1) * dp.get(n - 2) if x == 1 else dp.get(n - 1));
}
