public class Main {
    public static int countOfBinaryNumberLessThanN(int N) {
        Deque<Integer> q = new ArrayDeque<>();
        q.add(1);
        int cnt = 0;
        while (!q.isEmpty()) {
            int t = q.poll();
            if (t <= N) {
                cnt = cnt + 1;
                q.add(t * 10);
                q.add(t * 10 + 1);
            }
        }
        return cnt;
    }
}
