public class Main {
    static int getInvCount(int[] arr, int n) {
        int invcount = 0;
        for (int i = 1; i < n - 1; i++) {
            int small = 0;
            for (int j = i + 1; j < n; j++) {
                if (arr[i] > arr[j]) {
                    small += 1;
                }
            }
            int great = 0;
            for (int j = i - 1; j >= 0; j--) {
                if (arr[i] < arr[j]) {
                    great += 1;
                }
            }
            invcount += great * small;
        }
        return invcount;
    }

    public static void main(String[] args) {
        int[] arr = {1, 4, 3, 2};
        int n = arr.length;
        System.out.println(getInvCount(arr, n));
    }
}
