        int l = 0;
        int r = 0;
        while (r < n) {
            if (arr[r] - arr[l] == k) {
                count++;
                l++;
                r++;
            } else if (arr[r] - arr[l] > k) {
                l++;
            } else {
                r++;
            }
        }
        return count;
