public class Main {
    public static int findgroups(int[] arr, int n) {
        int[] c = new int[]{0, 0, 0};
        int res = 0;
        for (int i = 0; i < n; i++) {
            c[arr[i] % 3]++;
        }
        res += (c[0] * (c[0] - 1)) >> 1;
        res += c[1] * c[2];
        res += (c[0] * (c[0] - 1) * (c[0] - 2)) / 6;
        res += (c[1] * (c[1] - 1) * (c[1] - 2)) / 6;
        res += ((c[2] * (c[2] - 1) * (c[2] - 2)) / 6);
        res += c[0] * c[1] * c[2];
        return res;
    }
}
