import java.util.Stack;

public class Main {
    public static String decode(String Str) {
        Stack<Integer> integerstack = new Stack<>();
        Stack<String> stringstack = new Stack<>();
        String temp = "";
        String result = "";
        for (int i = 0; i < Str.length(); i++) {
            int count = 0;
            if (Str.charAt(i) >= '0' && Str.charAt(i) <= '9') {
                while (Str.charAt(i) >= '0' && Str.charAt(i) <= '9') {
                    count = count * 10 + Str.charAt(i) - '0';
                    i++;
                }
                i--;
                integerstack.push(count);
            } else if (Str.charAt(i) == ']') {
                temp = "";
                count = 0;
                if (!integerstack.isEmpty()) {
                    count = integerstack.pop();
                }
                while (!stringstack.isEmpty() && !stringstack.peek().equals("[")) {
                    temp = stringstack.pop() + temp;
                }
                if (!stringstack.isEmpty() && stringstack.peek().equals("[")) {
                    stringstack.pop();
                }
                for (int j = 0; j < count; j++) {
                    result = result + temp;
                }
                for (int j = 0; j < result.length(); j++) {
                    stringstack.push(String.valueOf(result.charAt(j)));
                }
                result = "";
            } else if (Str.charAt(i) == '[') {
                if (i > 0 && Str.charAt(i - 1) >= '0' && Str.charAt(i - 1) <= '9') {
                    stringstack.push(String.valueOf(Str.charAt(i)));
                } else {
                    stringstack.push(String.valueOf(Str.charAt(i)));
                    integerstack.push(1);
                }
            } else {
                stringstack.push(String.valueOf(Str.charAt(i)));
            }
        }
        while (!stringstack.isEmpty()) {
            result = stringstack.pop() + result;
        }
        return result;
    }

    public static void main(String[] args) {
        String input = "3[a]2[bc]";
        System.out.println(decode(input));  // Output: "aaabcbc"
    }
}
