        int cur = an;
        for (int i = 1; i <= n; i++) {
            if (value[cur] == 0) {
                value[cur] = i;
            }
            cur = (cur * an) % m;
        }
        cur = b;
        for (int i = 0; i <= n; i++) {
            if (value[cur] > 0) {
                int ans = value[cur] * n - i;
                if (ans < m) {
                    return ans;
                }
            }
            cur = (cur * a) % m;
        }
        return -1;
    }
}
