public class Main {
    public static void main(String[] args) {
        System.out.println(isDivisibleBy12("123456"));
    }

    public static boolean isDivisibleBy12(String num) {
        if (num.length() >= 3) {
            int d1 = Integer.parseInt(num.substring(num.length() - 1));
            if (d1 % 2 != 0) {
                return false;
            }
            int d2 = Integer.parseInt(num.substring(num.length() - 2, num.length() - 1));
            int sum = 0;
            for (int i = 0; i < num.length(); i++) {
                sum += Integer.parseInt(num.substring(i, i + 1));
            }
            return (sum % 3 == 0 && (d2 * 10 + d1) % 4 == 0);
        } else {
            int number = Integer.parseInt(num);
            return (number % 12 == 0);
        }
    }
}
