public class Solution {
    public int eggDrop(int n, int k) {
        int[][] eggFloor = new int[n + 1][k + 1];
        for (int i = 1; i <= n; i++) {
            eggFloor[i][1] = 1;
            eggFloor[i][0] = 0;
        }
        for (int j = 1; j <= k; j++) {
            eggFloor[1][j] = j;
        }
        for (int i = 2; i <= n; i++) {
            for (int j = 2; j <= k; j++) {
                eggFloor[i][j] = Integer.MAX_VALUE;
                for (int x = 1; x <= j; x++) {
                    int res = 1 + Math.max(eggFloor[i - 1][x - 1], eggFloor[i][j - x]);
