public class LongestBitonicSubsequence {
    public static int lbs(int[] arr, int n) {
        int[] lis = new int[n];
        int[] lds = new int[n];
        for (int i = 0; i < n; i++) {
            lis[i] = 1;
            lds[i] = 1;
        }

        for (int i = 1; i < n; i++) {
            for (int j = 0; j < i; j++) {
                if (arr[i] > arr[j] && lis[i] < lis[j] + 1) {
                    lis[i] = lis[j] + 1;
                }
            }
        }

        for (int i = n - 2; i >= 0; i--) {
            for (int j = n - 1; j > i; j--) {
                if (arr[i] > arr[j] && lds[i] < lds[j] + 1) {
                    lds[i] = lds[j] + 1;
                }
            }
        }

        int maximum = lis[0] + lds[0] - 1;
        for (int i = 1; i < n; i++) {
            maximum = Math.max(lis[i] + lds[i] - 1, maximum);
        }

        return maximum;
    }
}
