                    C[i][j] = 0;
                } else {
                    C[i][j] = 100000000;
                    for (k = i; k < j; k++) {
                        C[i][j] = Math.min(C[i][j], C[i][k] + C[k+1][j] + 1);
                    }
                }
            }
        }
        return C[0][n-1];
    }
