public class Solution {

    public static int findMinInsertions(String str, int l, int h) {
        if (l > h) {
            return Integer.MAX_VALUE;
        }
        if (l == h) {
            return 0;
        }
        if (l == h - 1) {
            return str.charAt(l) == str.charAt(h) ? 0 : 1;
        }
        if (str.charAt(l) == str.charAt(h)) {
            return findMinInsertions(str, l + 1, h - 1);
        } else {
            return Math.min(findMinInsertions(str, l, h - 1), findMinInsertions(str, l + 1, h)) + 1;
        }
    }

    public static void main(String[] args) {
        String str = "example";
        int minInsertions = findMinInsertions(str, 0, str.length() - 1);
        System.out.println("Minimum insertions required: " + minInsertions);
    }
}
