public class Main {
    public static int maxProd(int n) {
        if (n == 2 || n == 3) {
            return n - 1;
        }
        int res = 1;
        while (n > 4) {
            n -= 3;
            res *= 3;
        }
        return n * res;
    }

    public static void main(String[] args) {
        int n = 10;
        System.out.println(maxProd(n));
    }
}
