public class MatrixChainOrder {
    static int matrixChainOrder(int[] p, int i, int j) {
        if (i == j) {
            return 0;
        }
        int min = Integer.MAX_VALUE;
        for (int k = i; k < j; k++) {
            int count = (matrixChainOrder(p, i, k) + matrixChainOrder(p, k + 1, j) + p[i - 1] * p[k] * p[j]);
            if (count < min) {
                min = count;
            }
        }
        return min;
    }
}
