import java.util.Stack;

public class Main {
    public static boolean findDuplicateParenthesis(String string) {
        Stack<Character> stack = new Stack<>();
        for (char ch : string.toCharArray()) {
            if (ch == ')') {
                char top = stack.pop();
                int elementsInside = 0;
                while (top != '(') {
                    elementsInside++;
                    top = stack.pop();
                }
                if (elementsInside < 1) {
                    return true;
                }
            } else {
                stack.push(ch);
            }
        }
        return false;
    }

    public static void main(String[] args) {
        String input = "((a+b)+((c+d)))";
        System.out.println(findDuplicateParenthesis(input));
    }
}
