        S = Arrays.copyOfRange(S, 0, n);
        Arrays.sort(S);
        for (int i = n - 1; i >= 0; i--) {
            for (int j = 0; j < n; j++) {
                if (i == j) {
                    continue;
                }
                for (int k = j + 1; k < n; k++) {
                    if (i == k) {
                        continue;
                    }
                    for (int l = k + 1; l < n; l++) {
                        if (i == l) {
                            continue;
                        }
                        if (S[i] == S[j] + S[k] + S[l]) {
                            found = true;
                            return S[i];
                        }
                    }
                }
            }
        }
        if (!found) {
            return -1;
        }
    }
}
