import java.util.HashMap;
import java.util.Map;

public class Main {
    public static int findFourElements(int[] arr, int n) {
        Map<Integer, Integer> mp = new HashMap<>();
        for (int i = 0; i < n - 1; i++) {
            for (int j = i + 1; j < n; j++) {
                mp.put(arr[i] + arr[j], (i * n + j));
            }
        }
        int d = -1000000000;
        for (int i = 0; i < n - 1; i++) {
            for (int j = i + 1; j < n; j++) {
                int absDiff = Math.abs(arr[i] - arr[j]);
                if (mp.containsKey(absDiff)) {
                    int p = mp.get(absDiff);
                    int p0 = p / n;
                    int p1 = p % n;
                    if (p0 != i && p0 != j && p1 != i && p1 != j) {
                        d = Math.max(d, Math.max(arr[i], arr[j]));
                    }
                }
            }
        }
        return d;
    }

    public static void main(String[] args) {
