        for (int i = 0; i < n - 1; i++) {
            for (int j = i + 1; j < n; j++) {
                mp.put(arr[i] + arr[j], (i * n) + j);
            }
        }
        int d = -1000000000;
        for (int i = 0; i < n - 1; i++) {
            for (int j = i + 1; j < n; j++) {
                int abs_diff = Math.abs(arr[i] - arr[j]);
                if (mp.containsKey(abs_diff)) {
                    int p = mp.get(abs_diff);
                    if (p / n != i && p / n != j && p % n != i && p % n != j) {
                        d = Math.max(d, Math.max(arr[i], arr[j]));
                    }
                }
            }
        }
        return d;
    }

    public static void main(String[] args) {
        int[] arr = {1, 2, 3, 4, 5};
        int n = arr.length;
        System.out.println(findFourElements(arr, n));
