        int counter = 0;
        while (i < str.length()) {
            if (str.charAt(i) == '0' && last == '1') {
                while (str.charAt(i) == '0') {
                    i++;
                    if (str.charAt(i) == '1') {
                        counter++;
                    }
                }
            }
            last = str.charAt(i);
            i++;
        }
        return counter;
    }
