import java.util.HashMap;
import java.util.HashSet;
import java.util.Map;
import java.util.Set;

public class Main {
    public static boolean isRectangle(int[][] matrix) {
        int rows = matrix.length;
        if (rows == 0) {
            return false;
        }
        int columns = matrix[0].length;
        Map<Integer, Set<Integer>> table = new HashMap<>();
        for (int i = 0; i < rows; i++) {
            for (int j = 0; j < columns - 1; j++) {
                for (int k = j + 1; k < columns; k++) {
                    if (matrix[i][j] == 1 && matrix[i][k] == 1) {
                        if (table.containsKey(j) && table.get(j).contains(k)) {
                            return true;
                        }
                        if (table.containsKey(k) && table.get(k).contains(j)) {
                            return true;
                        }
                        table.putIfAbsent(j, new HashSet<>());
                        table.putIfAbsent(k, new HashSet<>());
                        table.get(j).add(k);
                        table.get(k).add(j);
                    }
                }
            }
        }
        return false;
    }
}
