        if (low > high) {
            return -1;
        }
        int mid = (low + high) / 2;
        if (arr[mid] != mid + 1) {
            if (mid > 0 && arr[mid] == arr[mid - 1]) {
                return mid;
            }
            return findRepeatingElement(arr, low, mid - 1);
        }
        return findRepeatingElement(arr, mid + 1, high);
    }
}
