public class Main {
    public static int singleNumber(int[] a, int n) {
        int sum = 0;
        for (int num : a) {
            sum += num;
        }
        return (3 * sumOfSet(a) - sum) / 2;
    }

    private static int sumOfSet(int[] a) {
        Set<Integer> set = new HashSet<>();
        for (int num : a) {
            set.add(num);
        }
        int sum = 0;
        for (int num : set) {
            sum += num;
        }
        return sum;
    }
}
