public class Solution {
    public int singleNumber(int[] a, int n) {
        int sumSet = 0;
        int sumA = 0;
        for (int num : a) {
            if (!contains(sumSet, num)) {
                sumSet += num;
            }
            sumA += num;
        }
        return (3 * sumSet - sumA) / 2;
    }

    private boolean contains(int sum, int num) {
        return (sum & num) != 0;
    }
}
