    public static boolean isPowerOfFour(int n) {
        int count = 0;
        if (n > 0 && (n & (n - 1)) == 0) {
            while (n > 1) {
                n >>= 1;
                count += 1;
            }
            if (count % 2 == 0) {
                return true;
            } else {
                return false;
            }
        }
        return false;
