public class Main {
    public static String getMinNumberForPattern(String seq) {
        int n = seq.length();
        if (n >= 9) {
            return "-1";
        }
        Integer[] result = new Integer[n + 1];
        int count = 1;
        for (int i = 0; i <= n; i++) {
            if (i == n || seq.charAt(i) == 'I') {
                for (int j = i - 1; j >= -1; j--) {
                    result[j + 1] = Integer.parseInt("0" + count);
                    count++;
                    if (j >= 0 && seq.charAt(j) == 'I') {
                        break;
                    }
                }
            }
        }
        StringBuilder sb = new StringBuilder();
        for (Integer num : result) {
            sb.append(num);
        }
        return sb.toString();
    }

    public static void main(String[] args) {
        String seq = "IDID";
        System.out.println(getMinNumberForPattern(seq)); // Output: 21435
    }
}
