public class Main {
    public static boolean isSubSeqDivisible(String str) {
        int l = str.length();
        int[] arr = new int[l];
        for (int i = 0; i < l; i++) {
            for (int j = i; j < l; j++) {
                for (int k = j; k < l; k++) {
                    if (arr[i] % 8 == 0) {
                        return true;
                    } else if ((arr[i] * 10 + arr[j]) % 8 == 0 && i != j) {
                        return true;
                    } else if ((arr[i] * 100 + arr[j] * 10 + arr[k]) % 8 == 0 && i != j && j != k && i != k) {
                        return true;
                    }
                }
            }
        }
        return false;
    }

    public static void main(String[] args) {
        String input = "123";
        System.out.println(isSubSeqDivisible(input));
