            if (arr[index] >= arr[index - 1]) {
                index = index + 1;
            } else {
                int temp = arr[index];
                arr[index] = arr[index - 1];
                arr[index - 1] = temp;
                index = index - 1;
            }
        }
        return arr;
    }
}
