public int maxRevenue(int m, int[] x, int[] revenue, int n, int t) {
    int[] maxRev = new int[m + 1];
    int nxtbb = 0;
    for (int i = 1; i <= m; i++) {
        if (nxtbb < n) {
            if (x[nxtbb] != i) {
                maxRev[i] = maxRev[i - 1];
            } else {
                if (i <= t) {
                    maxRev[i] = Math.max(maxRev[i - 1], revenue[nxtbb]);
                } else {
                    maxRev[i] = Math.max(maxRev[i - t - 1] + revenue[nxtbb], maxRev[i - 1]);
                }
                nxtbb += 1;
            }
        } else {
            maxRev[i] = maxRev[i - 1];
        }
    }
    return maxRev[m];
}
