import java.util.HashMap;

public class Main {
    public static int findInteger(int[] arr, int n) {
        HashMap<Integer, Integer> hash = new HashMap<>();
        int maximum = 0;
        for (int i : arr) {
            if (i < 0) {
                if (!hash.containsKey(Math.abs(i))) {
                    hash.put(Math.abs(i), -1);
                } else {
                    hash.put(Math.abs(i), hash.get(Math.abs(i)) - 1);
                }
            } else {
                hash.put(i, hash.getOrDefault(i, 0) + 1);
            }
        }
        for (int i : arr) {
            if (hash.containsKey(i) && hash.get(i) > 0) {
                return i;
            }
        }
        return -1;
    }
}
