    static int findSubArray(int[] arr, int n) {
        int sum = 0;
        int maxsize = -1;
        int startindex = 0;

        for (int i = 0; i < n - 1; i++) {
            sum = (arr[i] == 0) ? -1 : 1;

            for (int j = i + 1; j < n; j++) {
                sum += (arr[j] == 0) ? -1 : 1;
                if (sum == 0 && maxsize < j - i + 1) {
                    maxsize = j - i + 1;
                    startindex = i;
                }
            }
        }

        if (maxsize == -1) {
            System.out.println("No such subarray");
        } else {
            System.out.println(startindex + " to " + (startindex + maxsize - 1));
        }
        return maxsize;
    }

    public static void main(String[] args) {
        int[] arr = {0, 1, 0, 1, 0, 0, 1, 1};
        int n = arr.length;
        findSubArray(arr, n);
    }
}
