public class GCDSubsequence {
    public static int largestGCDSubsequence(int[] arr, int n) {
        int ans = 0;
        int maxele = 0;
        for (int num : arr) {
            maxele = Math.max(maxele, num);
        }
        for (int i = 2; i <= maxele; i++) {
            int count = 0;
            for (int j = 0; j < n; j++) {
                if (arr[j] % i == 0) {
                    count++;
                }
            }
            ans = Math.max(ans, count);
        }
        return ans;
    }
}
