public class Solution {
    public int maxLength(String s, int n) {
        int[][] dp = new int[n][n];
        for (int i = 0; i < n - 1; i++) {
            if (s.charAt(i) == '(' && s.charAt(i + 1) == ')') {
                dp[i][i + 1] = 2;
            }
        }
        for (int l = 2; l < n; l++) {
            int i = -1;
            for (int j = l; j < n; j++) {
                i++;
                if (s.charAt(i) == '(' && s.charAt(j) == ')') {
                    dp[i][j] = 2 + dp[i + 1][j - 1];
                }
                for (int k = i; k < j; k++) {
                    dp[i][j] = Math.max(dp[i][j], dp[i][k] + dp[k + 1][j]);
                }
            }
        }
        return dp[0][n - 1];
    }
}
