public class Main {
    public static int longestNull(String S) {
        List<char[]> arr = new ArrayList<>();
        arr.add(new char[]{'@', -1});
        int maxlen = 0;
        for (int i = 0; i < S.length(); i++) {
            arr.add(new char[]{S.charAt(i), i});
            while (arr.size() >= 3 && arr.get(arr.size() - 3)[0] == '1' && arr.get(arr.size() - 2)[0] == '0' && arr.get(arr.size() - 1)[0] == '0') {
                arr.remove(arr.size() - 1);
                arr.remove(arr.size() - 1);
                arr.remove(arr.size() - 1);
            }
            char[] tmp = arr.get(arr.size() - 1);
            maxlen = Math.max(maxlen, i - tmp[1]);
        }
        return maxlen;
    }
}
