        System.out.println(nextWord("abc")); // "abd"
    }

    public static String nextWord(String s) {
        if (s.equals(" ")) {
            return "a";
        }
        int i = s.length() - 1;
        while (i >= 0 && s.charAt(i) == 'z') {
            i--;
        }
        if (i == -1) {
            s = s + 'a';
        } else {
            char[] charArray = s.toCharArray();
            charArray[i] = (char) (charArray[i] + 1);
            s = new String(charArray);
        }
        return s;
    }
}
