        int n = str.length() - 1;
        int i = n;
        while (i > 0 && str.charAt(i - 1) <= str.charAt(i)) {
            i--;
        }
        if (i <= 0) {
            return false;
        }
        int j = i - 1;
        while (j + 1 <= n && str.charAt(j + 1) <= str.charAt(i - 1)) {
            j++;
        }
        char[] arr = str.toCharArray();
        char temp = arr[i - 1];
        arr[i - 1] = arr[j];
        arr[j] = temp;
        str = String.valueOf(arr);
        StringBuilder sb = new StringBuilder(str);
        str = sb.reverse().toString();
        return true;
    }
}
