public class LexicographicSubConcat {
    public String lexicographicSubConcat(String s) {
        int n = s.length();
        int subCount = (n * (n + 1)) / 2;
        String[] arr = new String[subCount];
        int index = 0;
        for (int i = 0; i < n; i++) {
            for (int j = 1; j <= n - i; j++) {
                arr[index] = s.substring(i, i + j);
                index++;
            }
        }
        Arrays.sort(arr);
        StringBuilder res = new StringBuilder();
        for (int i = 0; i < subCount; i++) {
            res.append(arr[i]);
        }
        return res.toString();
    }
}
