    public static int findLength(String str) {
        int n = str.length();
        int maxlen = 0;
        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j < n; j += 2) {
                int length = j - i + 1;
                int leftsum = 0;
                int rightsum = 0;
                for (int k = 0; k < length / 2; k++) {
                    leftsum += (Integer.parseInt(String.valueOf(str.charAt(i + k))) - Integer.parseInt("0"));
                    rightsum += (Integer.parseInt(String.valueOf(str.charAt(i + k + length / 2))) - Integer.parseInt("0"));
                }
                if (leftsum == rightsum && maxlen < length) {
                    maxlen = length;
                }
            }
        }
        return maxlen;
    }
}
