public class Solution {
    public int largestSumOfAverages(int[] A, int K) {
        int n = A.length;
        double[] preSum = new double[n + 1];
        preSum[0] = 0;
        for (int i = 0; i < n; i++) {
            preSum[i + 1] = preSum[i] + A[i];
        }
        double[] dp = new double[n];
        double sum = 0;
        for (int i = 0; i < n; i++) {
            dp[i] = (preSum[n] - preSum[i]) / (n - i);
        }
        for (int k = 0; k < K - 1; k++) {
            for (int i = 0; i < n; i++) {
                for (int j = i + 1; j < n; j++) {
                    dp[i] = Math.max(dp[i], (preSum[j] - preSum[i]) / (j - i) + dp[j]);
                }
            }
        }
        return (int) dp[0];
    }
}
