public class Main {
    public static int findLongestConseqSubseq(int[] arr, int n) {
        HashSet<Integer> S = new HashSet<>();
        for (int i = 0; i < n; i++) {
            S.add(arr[i]);
        }
        int ans = 0;
        for (int i = 0; i < n; i++) {
            if (S.contains(arr[i])) {
                int j = arr[i];
                while (S.contains(j)) {
                    j++;
                }
                ans = Math.max(ans, j - arr[i]);
            }
        }
        return ans;
    }
}
