public class Main {
    public static int maxdiff(int[] arr, int n) {
        HashMap<Integer, Integer> freq = new HashMap<>();
        for (int i = 0; i < n; i++) {
            freq.put(arr[i], freq.getOrDefault(arr[i], 0) + 1);
        }
        int ans = 0;
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n; j++) {
                if (freq.get(arr[i]) > freq.get(arr[j]) && arr[i] > arr[j]) {
                    ans = Math.max(ans, freq.get(arr[i]) - freq.get(arr[j]));
                } else if (freq.get(arr[i]) < freq.get(arr[j]) && arr[i] < arr[j]) {
                    ans = Math.max(ans, freq.get(arr[j]) - freq.get(arr[i]));
                }
            }
        }
        return ans;
    }

    public static void main(String[] args) {
        // Test the maxdiff function
        int[] arr = {3, 1, 2, 2, 3, 4};
        int n = arr.length;
        System.out.println(maxdiff(arr, n));  // Output: 2
    }
}
