        for (int i = 3; i < n; i++) {
            sum[i] = Math.max(Math.max(sum[i - 1], sum[i - 2] + arr[i]), arr[i] + arr[i - 1] + sum[i - 3]);
        }
        return sum[n - 1];
    }
}
