                } else if (arr[j] < arr[i] && flag == 1) {
                    inc[i] = Math.max(inc[i], dec[j] + arr[i]);
                }
            }
        }
        int result = Integer.MIN_VALUE;
        for (int i = 0; i < n; i++) {
            if (result < inc[i]) {
                result = inc[i];
            }
            if (result < dec[i]) {
                result = dec[i];
            }
        }
        return result;
    }

    public static void main(String[] args) {
        int[] arr = {1, 2, 3, 4, 5};
        int n = arr.length;
        System.out.println(maxAlternateSum(arr, n));
