public class Main {
    public static int maxSumBitonicSubArr(int[] arr, int n) {
        int[] msis = new int[n];
        int[] msds = new int[n];
        int max_sum = 0;
        msis[0] = arr[0];
        for (int i = 1; i < n; i++) {
            if (arr[i] > arr[i - 1]) {
                msis[i] = msis[i - 1] + arr[i];
            } else {
                msis[i] = arr[i];
            }
        }
        msds[n - 1] = arr[n - 1];
        for (int i = n - 2; i >= 0; i--) {
            if (arr[i] > arr[i + 1]) {
                msds[i] = msds[i + 1] + arr[i];
            } else {
                msds[i] = arr[i];
            }
        }
        for (int i = 0; i < n; i++) {
            if (max_sum < (msis[i] + msds[i] - arr[i])) {
                max_sum = (msis[i] + msds[i] - arr[i]);
            }
        }
        return max_sum;
    }

    public static void main(String[] args) {
        int[] arr = {1, 3, 5, 4, 2};
        int n = 5;
        System.out.println(maxSumBitonicSubArr(arr, n));
    }
}
