import java.util.Arrays;

public class Solution {
    public static int maxSumPairWithDifferenceLessThanK(int[] arr, int N, int k) {
        int maxSum = 0;
        Arrays.sort(arr);
        int i = N - 1;
        while (i > 0) {
            if (arr[i] - arr[i - 1] < k) {
                maxSum += arr[i];
                maxSum += arr[i - 1];
                i -= 1;
            }
            i -= 1;
        }
        return maxSum;
    }
}
