public class Solution {
    public int solve(String X, String Y, int l, int r, int k, int[][][] dp) {
        if (k == 0) {
            return 0;
        }
        if (l < 0 || r < 0) {
            return 1000000000;
        }
        if (dp[l][r][k] != -1) {
            return dp[l][r][k];
        }
        int cost = ((X.charAt(l) - 'a') ^ (Y.charAt(r) - 'a'));
        dp[l][r][k] = Math.min(cost + solve(X, Y, l - 1, r - 1, k - 1, dp), 
                               Math.min(solve(X, Y, l - 1, r, k, dp), solve(X, Y, l, r - 1, k, dp)));
        return dp[l][r][k];
    }
}
