public class SmallestSubWithSum {
    static int smallestSubWithSum(int[] arr, int n, int x) {
        int curr_sum = 0;
        int min_len = n + 1;
        int start = 0;
        int end = 0;
        while (end < n) {
            while (curr_sum <= x && end < n) {
                if (curr_sum <= 0 && x > 0) {
                    start = end;
                    curr_sum = 0;
                }
                curr_sum += arr[end];
                end++;
            }
            while (curr_sum > x && start < n) {
                if (end - start < min_len) {
                    min_len = end - start;
                }
                curr_sum -= arr[start];
                start++;
            }
        }
        return min_len;
    }
}
