class Main {
    static int minJumps(int[] arr, int n) {
        int[] jumps = new int[n];
        for (int i = n - 2; i >= 0; i--) {
            if (arr[i] == 0) {
                jumps[i] = Integer.MAX_VALUE;
            } else if (arr[i] >= n - i - 1) {
                jumps[i] = 1;
            } else {
                int min = Integer.MAX_VALUE;
                for (int j = i + 1; j < n; j++) {
                    if (j <= arr[i] + i) {
                        if (min > jumps[j]) {
                            min = jumps[j];
                        }
                    }
                }
                if (min != Integer.MAX_VALUE) {
                    jumps[i] = min + 1;
                } else {
                    jumps[i] = min;
                }
            }
        }
        return jumps[0];
    }

    public static void main(String[] args) {
        int[] arr = {2, 3, 1, 1, 2, 4, 2, 0, 1, 1};
        int n = arr.length;
        System.out.println(minJumps(arr, n));
