public class Subset {
    public static int subset(int[] ar, int n) {
        int res = 0;
        java.util.Arrays.sort(ar);
        int i = 0;
        while (i < n) {
            int count = 1;
            int j = i;
            while (j < n - 1) {
                if (ar[j] == ar[j + 1]) {
                    count++;
                } else {
                    break;
                }
                j++;
            }
            i = j;
            i++;
            res = Math.max(res, count);
        }
        return res;
    }
}
