public class Solution {
    public int findMinRooms (char[][] slots, int n, int m) {
        int[] counts = new int[m];
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < m; j++) {
                if (i < slots.length && j < slots[i].length) {
                    if (slots[i][j] == '1') {
                        counts[j] += 1;
                    }
                }
            }
        }
        int maxCount = 0;
        for (int count : counts) {
            maxCount = Math.max(maxCount, count);
        }
        return maxCount;
    }
}
