import java.util.Arrays;
import java.util.Deque;

public class Main {
    public static int minimumBox(int[] arr, int n) {
        Deque<Integer> q = new ArrayDeque<>();
        arr = Arrays.copyOfRange(arr, 0, n);
        Arrays.sort(arr);
        q.add(arr[0]);
        for (int i = 1; i < n; i++) {
            int now = q.peekFirst();
            if (arr[i] >= 2 * now) {
                q.pollFirst();
            }
            q.add(arr[i]);
        }
        return q.size();
    }
}
