        int[] factorCount = new int[n + 1];
        boolean[] prime = new boolean[n + 1];
        for (int i = 0; i <= n; i++) {
            factorCount[i] = 0;
            prime[i] = true;
        }
        for (int i = 2; i <= n; i++) {
            if (prime[i]) {
                factorCount[i] = 1;
                for (int j = i * 2; j <= n; j += i) {
                    factorCount[j]++;
                    prime[j] = false;
                }
            }
        }
        int max = factorCount[m];
        int num = m;
        for (int i = m; i <= n; i++) {
            if (factorCount[i] > max) {
                max = factorCount[i];
                num = i;
            }
        }
        return num;
    }
}
