public class PangramChecker {
    public static boolean checkPangram(String s) {
        boolean[] list = new boolean[26];
        for (int i = 0; i < 26; i++) {
            list[i] = false;
        }
        for (char c : s.toCharArray()) {
            if ('A' <= c && c <= 'Z') {
                list[c - 'A'] = true;
            } else if ('a' <= c && c <= 'z') {
                list[c - 'a'] = true;
            }
        }
        for (boolean ch : list) {
            if (!ch) {
                return false;
            }
        }
        return true;
    }
}
