public class Main {
    public static int maxDifference(int[] arr, int N, int k) {
        int S = 0;
        int S1 = 0;
        int max_difference = 0;
        for (int i = 0; i < N; i++) {
            S += arr[i];
        }
        Arrays.sort(arr);
        int M = Math.max(k, N - k);
        for (int i = N - 1; i >= N - M; i--) {
            S1 += arr[i];
        }
        max_difference = S1 - (S - S1);
        return max_difference;
    }
}
