public class Main {
    public static boolean isPossibleTriangle(int[] arr, int N) {
        int[] copyArr = Arrays.copyOf(arr, N);
        if (N < 3) {
            return false;
        }
        Arrays.sort(copyArr);
        for (int i = 0; i < N - 2; i++) {
            if (copyArr[i] + copyArr[i + 1] > copyArr[i + 2]) {
                return true;
            }
        }
        return false;
    }
}
