    public static boolean isPossibleTriangle(int[] arr, int N) {
        int[] newArr = Arrays.copyOf(arr, N);
        if (N < 3) {
            return false;
        }
        Arrays.sort(newArr);
        for (int i = 0; i < N - 2; i++) {
            if (newArr[i] + newArr[i + 1] > newArr[i + 2]) {
                return true;
            }
        }
        return false;
    }
}
