        int k = 0;
        int l = 0;
        int[] stk = new int[m * n];
        int index = 0;
        while (k <= m && l <= n) {
            for (int i = l; i <= n; i++) {
                stk[index++] = a[k][i];
            }
            k++;
            for (int i = k; i <= m; i++) {
                stk[index++] = a[i][n];
            }
            n--;
            if (k <= m) {
                for (int i = n; i >= l; i--) {
                    stk[index++] = a[m][i];
                }
                m--;
            }
            if (l <= n) {
                for (int i = m; i >= k; i--) {
                    stk[index++] = a[i][l];
                }
                l++;
            }
        }
        for (int i = index - 1; i >= 0; i--) {
            System.out.print(stk[i] + " ");
        }
    }
}
