import java.util.HashMap;

public class Main {

    public static int findMaximum(int[] a, int n, int k) {
        HashMap<Integer, Integer> b = new HashMap<>();
        for (int i = 0; i < n; i++) {
            int x = a[i];
            int d = Math.min(1 + i, n - i);
            if (!b.containsKey(x)) {
                b.put(x, d);
            } else {
                b.put(x, Math.min(d, b.get(x)));
            }
        }
        int ans = Integer.MAX_VALUE;
        for (int i = 0; i < n; i++) {
            int x = a[i];
            if (x != (k - x) && b.containsKey(k - x)) {
                ans = Math.min(Math.max(b.get(x), b.get(k - x)), ans);
            }
        }
        return ans;
    }

    public static void main(String[] args) {
        int[] a = {2, 7, 2, 4, 3};
        int n = a.length;
        int k = 5;
        System.out.println(findMaximum(a, n, k));
    }
}
