public class ISBNValidator {
    public static boolean isValidISBN(String isbn) {
        if (isbn.length() != 10) {
            return false;
        }
        int _sum = 0;
        for (int i = 0; i < 9; i++) {
            if (Character.isDigit(isbn.charAt(i))) {
                _sum += Character.getNumericValue(isbn.charAt(i)) * (10 - i);
            } else {
                return false;
            }
        }
        if (!(isbn.charAt(9) == 'X' || Character.isDigit(isbn.charAt(9)))) {
            return false;
        }
        _sum += (isbn.charAt(9) == 'X') ? 10 : Character.getNumericValue(isbn.charAt(9));
        return (_sum % 11 == 0);
    }
}
