public class Main {
    public static void main(String[] args) {
        int n = 123;
        int dec_value = octalToDecimal(n);
        System.out.println("Decimal equivalent: " + dec_value);
    }

    public static int octalToDecimal(int n) {
        int num = n;
        int dec_value = 0;
        int base = 1;
        int temp = num;
        while (temp != 0) {
            int last_digit = temp % 10;
            temp = temp / 10;
            dec_value += last_digit * base;
            base = base * 8;
        }
        return dec_value;
    }
}
