        for (int i = 0; i < n; i++) {
            System.out.print((i + 1) + "         " + processSize[i] + "     ");
            if (allocation[i] != 0) {
                System.out.println(allocation[i] + 1);
            } else {
                System.out.println("Not Allocated");
            }
        }
    }
}
