public class Rearrange {
    public int[] rearrange(int[] arr, int n) {
        int[] temp = new int[n];
        int small = 0, large = n - 1;
        boolean flag = true;
        for (int i = 0; i < n; i++) {
            if (flag) {
                temp[i] = arr[large];
                large--;
            } else {
                temp[i] = arr[small];
                small++;
            }
            flag = !flag;
        }
        for (int i = 0; i < n; i++) {
            arr[i] = temp[i];
        }
        return arr;
    }
}
