public class Solution {
    public String simplify(String Str) {
        int Len = Str.length();
        char[] res = new char[Len];
        int index = 0;
        int i = 0;
        List<Character> s = new ArrayList<>();
        s.add('0');
        while (i < Len) {
            if (Str.charAt(i) == '+') {
                if (s.get(s.size() - 1) == '1') {
                    res[index] = '-';
                    index++;
                }
                if (s.get(s.size() - 1) == '0') {
                    res[index] = '+';
                    index++;
                }
            } else if (Str.charAt(i) == '-') {
                if (s.get(s.size() - 1) == '1') {
                    res[index] = '+';
                    index++;
                } else if (s.get(s.size() - 1) == '0') {
                    res[index] = '-';
                    index++;
                }
            } else if (Str.charAt(i) == '(' && i > 0) {
                if (Str.charAt(i - 1) == '-') {
                    char x = (s.get(s.size() - 1) == '1') ? '0' : '1';
                    s.add(x);
                } else if (Str.charAt(i - 1) == '+') {
                    s.add(s.get(s.size() - 1));
                }
            } else if (Str.charAt(i) == ')') {
                s.remove(s.size() - 1);
            } else {
                res[index] = Str.charAt(i);
                index++;
            }
            i++;
        }
        return new String(res, 0, index);
    }
}
