public class BitonicGenerator {
    void bitonicGenerator(int[] arr, int n) {
        int[] evenArr = new int[n / 2 + n % 2];
        int[] oddArr = new int[n / 2];
        int evenIndex = 0;
        int oddIndex = 0;
        for (int i = 0; i < n; i++) {
            if (i % 2 == 0) {
                evenArr[evenIndex++] = arr[i];
            } else {
                oddArr[oddIndex++] = arr[i];
            }
        }
        Arrays.sort(evenArr, 0, evenIndex);
        Arrays.sort(oddArr, 0, oddIndex);
        reverseArray(oddArr, oddIndex);
        int i = 0;
        for (int j = 0; j < evenIndex; j++) {
            arr[i++] = evenArr[j];
        }
        for (int j = 0; j < oddIndex; j++) {
            arr[i++] = oddArr[j];
        }
    }

    void reverseArray(int[] arr, int n) {
        for (int i = 0; i < n / 2; i++) {
            int temp = arr[i];
            arr[i] = arr[n - i - 1];
            arr[n - i - 1] = temp;
        }
    }
}
