public class KnapSack {
    public static int knapSack(int[] val, int[] wt, int n, int W) {
        int[][] mat = new int[2][W + 1];
        int i = 0;
        while (i < n) {
            int j = 0;
            if (i % 2 == 0) {
                while (j < W) {
                    j++;
                    if (wt[i] <= j && j - wt[i] < W) {
                        mat[1][j] = Math.max(val[i] + mat[0][j - wt[i]], mat[0][j]);
                    } else {
                        mat[1][j] = mat[0][j];
                    }
                }
            } else {
                while (j < W) {
                    j++;
                    if (wt[i] <= j && j - wt[i] < W) {
                        mat[0][j] = Math.max(val[i] + mat[1][j - wt[i]], mat[1][j]);
                    } else {
                        mat[0][j] = mat[1][j];
                    }
                }
            }
            i++;
        }
        if (n % 2 == 0) {
            return mat[0][W];
        } else {
            return mat[1][W];
        }
    }
}
