public class Main {
    public static int sumoflength(int[] arr, int n) {
        List<Integer> s = new ArrayList<>();
        int j = 0;
        int ans = 0;
        for (int i = 0; i < n; i++) {
            while (j < n && !s.contains(arr[j])) {
                s.add(arr[j]);
                j++;
            }
            ans += ((j - i) * (j - i + 1)) / 2;
            s.remove(Integer.valueOf(arr[i]));
        }
        return ans;
    }
}
