public class Main {
    public static int MaxTotalRectangleArea(int[] a, int n) {
        a = Arrays.copyOf(a, n);
        Arrays.sort(a);
        int sum = 0;
        boolean flag = false;
        int len = 0;
        int i = 0;
        while (i < n - 1) {
            if ((a[i] == a[i + 1] || a[i] - a[i + 1] == 1) && !flag) {
                flag = true;
                len = a[i + 1];
                i = i + 1;
            } else if ((a[i] == a[i + 1] || a[i] - a[i + 1] == 1) && flag) {
                sum = sum + a[i + 1] * len;
                flag = false;
                i = i + 1;
            }
            i += 1;
        }
        return sum;
    }
}
