                i = i + 1;
            } else if ((arr[i] == arr[i + 1] || arr[i] - arr[i + 1] == 1) && flag) {
                sum = sum + arr[i + 1] * len;
                flag = false;
                i = i + 1;
            }
            i += 1;
        }
        return sum;
    }

    public static void main(String[] args) {
        int[] a = {1, 2, 2, 3, 3, 3, 4, 4, 5};
        int n = 9;
        System.out.println(MaxTotalRectangleArea(a, n));
    }
}
