public class Main {
    public static int divSum(int n) {
        int result = 0;
        for (int i = 2; i <= (int) (Math.sqrt(n)) + 1; i++) {
            if (n % i == 0) {
                if (i == (n / i)) {
                    result = result + i;
                } else {
                    result = result + (i + n / i);
                }
            }
        }
        return (result + n + 1);
    }
