        String str1 = "123";
        String str2 = "456";
        System.out.println(findSum(str1, str2));
    }

    public static String findSum(String str1, String str2) {
        if (str1.length() > str2.length()) {
            String t = str1;
            str1 = str2;
            str2 = t;
        }
        String str = "";
        int n1 = str1.length();
        int n2 = str2.length();
        str1 = new StringBuilder(str1).reverse().toString();
        str2 = new StringBuilder(str2).reverse().toString();
        int carry = 0;
        for (int i = 0; i < n1; i++) {
            int sum = ((str1.charAt(i) - '0') + ((str2.charAt(i) - '0') + carry));
            if (sum < 0) {
                str += (char) (sum % -10 + '0');
            } else {
                str += (char) (sum % 10 + '0');
            }
            carry = (int) (sum / 10);
        }
        for (int i = n1; i < n2; i++) {
            int sum = ((str2.charAt(i) - '0') + carry);
            if (sum < 0) {
                str += (char) (sum % -10 + '0');
            } else {
                str += (char) (sum % 10 + '0');
            }
            carry = (int) (sum / 10);
        }
        if (carry > 0) {
            str += (char) (carry + '0');
        }
        str = new StringBuilder(str).reverse().toString();
        return str;
    }
}
