public class Main {
    public static void main(String[] args) {
        System.out.println(isMultipleOf3(10));
    }

    public static int isMultipleOf3(int n) {
        int oddCount = 0;
        int evenCount = 0;
        if (n < 0) {
            n = -n;
        }
        if (n == 0) {
            return 1;
        }
        if (n == 1) {
            return 0;
        }
        while (n != 0) {
            if ((n & 1) == 1) {
                oddCount++;
            }
            if ((n & 2) == 2) {
                evenCount++;
            }
            n = n >> 2;
        }
        return isMultipleOf3(Math.abs(oddCount - evenCount));
    }
}
